  uint64_t mask;
  if (n_leading_bits_ == 0) {
    mask = ~0ULL;  // All 1s (no bits to mask)
  } else {
    mask = (1ULL << (64 - n_leading_bits_)) - 1;
  }
  uint64_t remaining = hash & mask;

  // Calculate position: count trailing zeros in remaining
  int position;
  if (remaining == 0) {
    // All zeros: position is the number of remaining bits
    position = 64 - n_leading_bits_;
  } else {
    // Count trailing zeros
    int trailing_zeros = 0;
    uint64_t temp = remaining;
    while ((temp & 1) == 0) {
      trailing_zeros++;
      temp >>= 1;
    }
    position = trailing_zeros;
  }

  // Now store this value using dense_bucket_ (4 bits) and overflow_bucket_ (3 bits)
  // Total 7 bits can represent values 0-127
  // Dense bucket stores lower 4 bits
  // Overflow bucket stores upper 3 bits

  // Current value in registers
  uint64_t current_dense = dense_bucket_[bucket_idx].to_ullong();
  uint64_t current_overflow = 0;
  if (overflow_bucket_.find(bucket_idx) != overflow_bucket_.end()) {
    current_overflow = overflow_bucket_[bucket_idx].to_ullong();
  }
  uint64_t current_value = (current_overflow << DENSE_BUCKET_SIZE) | current_dense;

  // Update if new position is larger
  if (static_cast<uint64_t>(position) > current_value) {
    // Store new value
    uint64_t new_dense = static_cast<uint64_t>(position) & 0xF;  // Lower 4 bits
    uint64_t new_overflow = (static_cast<uint64_t>(position) >> DENSE_BUCKET_SIZE) & 0x7;  // Upper 3 bits

    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(new_dense);
    if (new_overflow > 0) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(new_overflow);
    }
  }
}

/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_leading_bits_ < 0 || dense_bucket_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Number of buckets
  size_t m = dense_bucket_.size();

  // Compute the harmonic mean: sum of 2^(-M[j])
  double sum = 0.0;
  for (size_t j = 0; j < m; j++) {
    uint64_t dense_val = dense_bucket_[j].to_ullong();
    uint64_t overflow_val = 0;
    if (overflow_bucket_.find(static_cast<uint16_t>(j)) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[static_cast<uint16_t>(j)].to_ullong();
    }
    uint64_t register_val = (overflow_val << DENSE_BUCKET_SIZE) | dense_val;
    sum += std::pow(2.0, -static_cast<double>(register_val));
  }

  // Cardinality = CONSTANT * m^2 / sum
  double raw_estimate = CONSTANT * static_cast<double>(m) * static_cast<double>(m) / sum;

  cardinality_ = static_cast<uint64_t>(raw_estimate);
}

template class HyperLogLogPresto<int64_t>;
