#include "primer/hyperloglog_presto.h"
#include <cmath>

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : cardinality_(0), n_leading_bits_(n_leading_bits) {
  // If n_leading_bits is invalid (negative), treat as 0
  if (n_leading_bits_ < 0) {
    n_leading_bits_ = -1;  // Mark as invalid
    dense_bucket_.resize(0);
  } else {
    // Number of buckets is 2^n_leading_bits
    size_t num_buckets = 1ULL << n_leading_bits_;
    dense_bucket_.resize(num_buckets, std::bitset<DENSE_BUCKET_SIZE>(0));
  }
}

/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ < 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Get hash value
  hash_t hash = CalculateHash(val);

  // Extract bucket index from the FIRST n_leading_bits (MSB side)
  // For a 64-bit hash, the top bits determine the bucket
  uint16_t bucket_idx = 0;
  if (n_leading_bits_ > 0) {
    bucket_idx = static_cast<uint16_t>(hash >> (64 - n_leading_bits_));
  }

  // Calculate position of leftmost 1 in the remaining bits
  // Clear the top n_leading_bits_ from the hash
  hash_t remaining;
  if (n_leading_bits_ >= 64) {
    remaining = 0;
  } else {
    // Mask out the top n_leading_bits_ bits
    if (n_leading_bits_ == 0) {
      remaining = hash;
    } else {
      remaining = hash << n_leading_bits_;
    }
  }

  // Count leading zeros + 1 to get position of leftmost 1
  uint64_t position;
  if (remaining == 0) {
    // All zeros, position is at the end
    position = 64 - n_leading_bits_ + 1;
  } else {
    // Find position of leftmost 1 (1-indexed)
    position = 1;
    for (int i = 63; i >= 0; i--) {
      if ((remaining >> i) & 1) {
        break;
      }
      position++;
    }
  }

  // Now store this value using dense_bucket_ (4 bits) and overflow_bucket_ (3 bits)
  // Total 7 bits can represent values 0-127
  // Dense bucket stores lower 4 bits
  // Overflow bucket stores upper 3 bits

  // Current value in registers
  uint64_t current_dense = dense_bucket_[bucket_idx].to_ullong();
  uint64_t current_overflow = 0;
  if (overflow_bucket_.find(bucket_idx) != overflow_bucket_.end()) {
    current_overflow = overflow_bucket_[bucket_idx].to_ullong();
  }
  uint64_t current_value = (current_overflow << DENSE_BUCKET_SIZE) | current_dense;

  // Update if new position is larger
  if (position > current_value) {
    // Store new value
    uint64_t new_dense = position & 0xF;  // Lower 4 bits
    uint64_t new_overflow = (position >> DENSE_BUCKET_SIZE) & 0x7;  // Upper 3 bits

    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(new_dense);
    if (new_overflow > 0) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(new_overflow);
    }
  }
}

/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_leading_bits_ < 0 || dense_bucket_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Number of buckets
  size_t m = dense_bucket_.size();

  // Compute the harmonic mean: sum of 2^(-M[j])
  double sum = 0.0;
  for (size_t j = 0; j < m; j++) {
    uint64_t dense_val = dense_bucket_[j].to_ullong();
    uint64_t overflow_val = 0;
    if (overflow_bucket_.find(static_cast<uint16_t>(j)) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[static_cast<uint16_t>(j)].to_ullong();
    }
    uint64_t register_val = (overflow_val << DENSE_BUCKET_SIZE) | dense_val;
    sum += std::pow(2.0, -static_cast<double>(register_val));
  }

  // Cardinality = CONSTANT * m^2 / sum
  double raw_estimate = CONSTANT * static_cast<double>(m) * static_cast<double>(m) / sum;

  cardinality_ = static_cast<uint64_t>(raw_estimate);
}

template class HyperLogLogPresto<int64_t>;
template class HyperLogLogPresto<std::string>;
}  // namespace bustub

